#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#define MAX_N 100000
#define MAX_T 5

int compare(const void *a, const void *b) {
    int *x1 = (int *)a;
    int *x2 = (int *)b;
    return x1[0] - x2[0];
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int n;
        scanf("%d", &n);
        int tracks[n][2];
        for (int i = 0; i < n; i++) {
            scanf("%d %d", &tracks[i][0], &tracks[i][1]);
        }
        qsort(tracks, n, sizeof(tracks[0]), compare);
        int max_length = -1;
        char directions[n];
        for (int i = 0; i < n; i++) {
            int length = 0;
            for (int j = i - 1; j >= 0; j--) {
                if (tracks[j][0] == tracks[i][0]) {
                    length = max(length, tracks[i][1] - tracks[j][1]);
                }
            }
            for (int j = i + 1; j < n; j++) {
                if (tracks[j][0] == tracks[i][0]) {
                    length = max(length, tracks[j][1] - tracks[i][1]);
                }
            }
            if (length == 0) {
                directions[i] = '-';
            } else {
                directions[i] = '|';
            }
            max_length = max(max_length, length);
        }
        printf("%d\n", max_length);
        for (int i = 0; i < n; i++) {
            printf("%c", directions[i]);
        }
        printf("\n");
    }
    return 0;
}

