#include <iostream>
#include <algorithm>
using namespace std;
#define MAX_N 100000
#define MAX_T 5

struct Track {
    int x, y;
};

bool compare(Track a, Track b) {
    return a.x < b.x;
}

int main() {
    int T;
    cin >> T;
    for (int t = 0; t < T; t++) {
        int n;
        cin >> n;
        Track tracks[n];
        for (int i = 0; i < n; i++) {
            cin >> tracks[i].x >> tracks[i].y;
        }
        sort(tracks, tracks + n, compare);
        int max_length = -1;
        char directions[n];
        for (int i = 0; i < n; i++) {
            int length = 0;
            for (int j = i - 1; j >= 0; j--) {
                if (tracks[j].x == tracks[i].x) {
                    length = max(length, tracks[i].y - tracks[j].y);
                }
            }
            for (int j = i + 1; j < n; j++) {
                if (tracks[j].x == tracks[i].x) {
                    length = max(length, tracks[j].y - tracks[i].y);
                }
            }
            if (length == 0) {
                directions[i] = '-';
            } else {
                directions[i] = '|';
            }
            max_length = max(max_length, length);
        }
        cout << max_length << endl;
        for (int i = 0; i < n; i++) {
            cout << directions[i];
        }
        cout << endl;
    }
    return 0;
}

