import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int n = scanner.nextInt();
            int[][] tracks = new int[n][2];
            for (int i = 0; i < n; i++) {
                tracks[i][0] = scanner.nextInt();
                tracks[i][1] = scanner.nextInt();
            }
            Arrays.sort(tracks, (a, b) -> a[0] - b[0]);
            int max_length = -1;
            char[] directions = new char[n];
            for (int i = 0; i < n; i++) {
                int length = 0;
                for (int j = i - 1; j >= 0; j--) {
                    if (tracks[j][0] == tracks[i][0]) {
                        length = Math.max(length, tracks[i][1] - tracks[j][1]);
                    }
                }
                for (int j = i + 1; j < n; j++) {
                    if (tracks[j][0] == tracks[i][0]) {
                        length = Math.max(length, tracks[j][1] - tracks[i][1]);
                    }
                }
                if (length == 0) {
                    directions[i] = '-';
                } else {
                    directions[i] = '|';
                }
                max_length = Math.max(max_length, length);
            }
            System.out.println(max_length);
            for (int i = 0; i < n; i++) {
                System.out.print(directions[i]);
            }
            System.out.println();
        }
    }
}

